feed:
{{ $siteTitle := .Site.Title | plainify | htmlEscape }}
	{{ $siteTitle }}
	{{ with .OutputFormats.Get "RSS" }}
	{{ end }}
	tag:{{ $siteTitle }},{{ .Date.Format "2006-01-02" }}:/
	{{ .Site.Lastmod.UTC.Format "2006-01-02T15:04:05-07:00" | safeHTML }}{{ with hugo.Data.site }}
	{{ with .description }}{{ . | plainify | htmlEscape }}{{ end }}{{ end }}{{ with hugo.Data.author }}{{ with .avatar }}
	{{ . | absURL }}
	{{ . | absURL}}{{ end }}{{ end }}

	{{ range first 10 .Site.RegularPages }}
		{{ .Title | plainify | htmlEscape }}{{ with .Section }}{{ $secURL := printf "/%s/" . | urlize }}
		{{ end }}

		tag:{{ $siteTitle }},{{ .Date.Format "2006-01-02" }}:{{ .RelPermalink }}
		{{ .Date.UTC.Format "2006-01-02T15:04:05-07:00" | safeHTML }}
		{{ .Lastmod.UTC.Format "2006-01-02T15:04:05-07:00" | safeHTML }}{{ with .Description }}
		{{ . | plainify | htmlEscape }}{{ end }}{{ with hugo.Data.author }}

			{{ with .name }}{{ . | plainify | htmlEscape }}{{ end }}
			{{ with .url }}{{ . }}{{ end }}

		{{ partial "ccl-rss.html" .license }}{{ end }}
		{{ .Content | html }}
	{{ end }}
